async (params, browser) => {
  // Open CoinMarketCap crypto news page
  await browser.open('https://coinmarketcap.com/academy/categories/cmc-crypto-news')

  // Wait for news articles to load
  await browser.waitForSelector('a[href*=\'/academy/article/\'], article, h2, h3', 15000)

  // Let articles render
  await browser.wait(2500)

  // Scroll to load more articles
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract news articles
  const news_data = await browser.evaluate(`const articles = []; const links = document.querySelectorAll('a[href*="/academy/article/"]'); const seen = new Set(); for (let i = 0; i < links.length; i++) { const link = links[i]; const href = link.href; if (seen.has(href)) continue; seen.add(href); const container = link.closest('article, div, li') || link; const titleEl = container.querySelector('h2, h3, h4') || link.querySelector('h2, h3, h4'); const title = titleEl ? titleEl.textContent.trim() : link.textContent.trim(); if (!title || title.length < 5) continue; const dateEl = container.querySelector('time, [datetime]'); const summaryEl = container.querySelector('p'); const imgEl = container.querySelector('img'); articles.push({ title: title, date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', summary: summaryEl ? summaryEl.textContent.trim().substring(0, 300) : '', image: imgEl ? (imgEl.src || imgEl.dataset.src || '') : '', url: href }); if (articles.length >= 20) break; } return { article_count: articles.length, articles: articles, url: window.location.href }`)

  return news_data
}
